# 문제 - 구구구단을 출력해주세요.
# 조건 - 3단까지만 출력해주세요.
# 출력양식
'''
== 1단 ==
1 * 1 * 1 = 1
1 * 1 * 2 = 2
1 * 1 * 3 = 3
1 * 2 * 1 = 2
1 * 2 * 2 = 4
1 * 2 * 3 = 6
1 * 3 * 1 = 3
1 * 3 * 2 = 6
1 * 3 * 3 = 9
== 2단 ==
2 * 1 * 1 = 2
2 * 1 * 2 = 4
2 * 1 * 3 = 6
2 * 2 * 1 = 4
2 * 2 * 2 = 8
2 * 2 * 3 = 12
2 * 3 * 1 = 6
2 * 3 * 2 = 12
2 * 3 * 3 = 18
== 3단 ==
3 * 1 * 1 = 3
3 * 1 * 2 = 6
3 * 1 * 3 = 9
3 * 2 * 1 = 6
3 * 2 * 2 = 12
3 * 2 * 3 = 18
3 * 3 * 1 = 9
3 * 3 * 2 = 18
3 * 3 * 3 = 27
'''

for i in range(1, 4):
  print(f"== {i}단 ==")
  for j in range(1, 4):
    for k in range(1, 4):
      print(f"{i} * {j} * {k} = {i * j * k}")
    k += 1
  j += 1
i += 1